import Image from "next/image";

// shadcn
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";

// constants
const portfolioItems = [
  {
    title: "First one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    image: "https://cdn.uiable.com/block/g1.jpg",
  },
  {
    title: "Second one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    image: "https://cdn.uiable.com/block/g2.jpg",
  },
  {
    title: "Third one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    image: "https://cdn.uiable.com/block/g3.jpg",
  },
  {
    title: "Fourth one",
    description:
      "At half-past eight the door opened, the policeman appeared and requesting them to follow him.",
    image: "https://cdn.uiable.com/block/g4.jpg",
  },
];

//  ------------------------------ | GALLERY 8 | ------------------------------  //

export default function Gallery7() {
  return (
    <section className="py-16 md:py-24">
      <div className="container px-4 mx-auto">
        <div className="grid grid-cols-12 gap-y-6">
          {/* Header Section */}
          <div className="col-span-12 text-center flex flex-col items-center gap-4">
            <h2>Portfolio</h2>
            <p className="text-slate-500 text-sm md:text-lg max-w-2xl">
              At half-past eight the door opened, the policeman appeared and
              requesting them to follow him, led way to an adjoining hall.
            </p>
          </div>

          {/* Carousel Section */}
          <div className="col-span-12 px-12 md:px-16">
            <Carousel opts={{ align: "start", loop: true }} className="w-full">
              <CarouselContent className="-ml-8">
                {portfolioItems.map((item, index) => (
                  <CarouselItem
                    key={index}
                    className="pl-8 basis-full md:basis-1/2"
                  >
                    <div className="flex flex-col gap-6 text-center items-center">
                      {/* Image Container */}
                      <div className="overflow-hidden rounded-3xl w-full">
                        <div className="relative aspect-4/3">
                          <Image
                            src={item.image}
                            alt={item.title}
                            fill
                            className="object-cover"
                          />
                        </div>
                      </div>

                      {/* Content Section */}
                      <div className="flex flex-col gap-2 max-w-md">
                        <h4>{item.title}</h4>
                        <p className="text-slate-500 text-sm md:text-md">
                          {item.description}
                        </p>
                      </div>
                    </div>
                  </CarouselItem>
                ))}
              </CarouselContent>
              <CarouselPrevious className="hidden md:flex" />
              <CarouselNext className="hidden md:flex" />
            </Carousel>
          </div>
        </div>
      </div>
    </section>
  );
}
